fn solve(s: String) -> Vec<String> {
    let mut segments = Vec::new();
    let mut seen = std::collections::HashSet::new();
    let mut current_segment = Vec::new();
    let s_bytes = s.into_bytes();
    let mut i = 0;

    while i < s_bytes.len() {
        current_segment.push(s_bytes[i]);
        let current_str = std::str::from_utf8(&current_segment).unwrap();
        if seen.contains(current_str) {
            segments.push(current_str.to_string());
            current_segment = Vec::new();
            seen.insert(current_str.to_string());
        } else {
            seen.insert(current_str.to_string());
        }
        i += 1;
    }

    if !current_segment.is_empty() {
        segments.push(std::str::from_utf8(&current_segment).unwrap().to_string());
    }

    segments
}
